const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=parseInt(input[idx++]);
let out=[];
for(let t=0;t<T;t++){
  const N=parseInt(input[idx++]);
  const X=parseInt(input[idx++]);
  const K=BigInt(input[idx++]);
  const A=new Array(N);
  const B=new Array(N);
  for(let i=0;i<N;i++) A[i]=BigInt(input[idx++]);
  for(let i=0;i<N;i++) B[i]=BigInt(input[idx++]);
  let cnt=0;
  for(let i=0;i<N;i++){
    const diff = A[i]>=B[i]?A[i]-B[i]:B[i]-A[i];
    if(diff<=K) cnt++;
  }
  out.push(cnt>=X?'YES':'NO');
}
console.log(out.join('\n'));

